<?php require_once 'db.php'; $u=require_login('student'); $s=pdo()->prepare('SELECT b.*,t.table_code FROM bookings b JOIN library_tables t ON t.id=b.table_id WHERE b.student_id=? ORDER BY b.id DESC LIMIT 6'); $s->execute([$u['id']]); app_header('Student Dashboard'); ?><section class="dash"><div class="card"><h1>Welcome, <?=e($u['name'])?></h1><p>Book study tables and track approvals.</p><a class="btn" href="table_booking.php">Book a table</a></div><div class="card"><h2>Recent bookings</h2><?php foreach($s as $b): ?><p><b><?=e($b['table_code'])?></b> — <?=e($b['status'])?> — ₹<?=e($b['amount'])?></p><?php endforeach; ?></div></section><?php app_footer(); ?>
